options.customCss:
:root {
  /* ── Tema Azul Profesional ── */
  /* Primary: azul medio / acero */
  --chat--color-primary: #2A6F9C;
  --chat--color-primary-shade-50: #235E84;
  --chat--color-primary-shade-100: #1C4D6B;

  /* Secondary: azul marino / medianoche */
  --chat--color-secondary: #0D2B3E;
  --chat--color-secondary-shade-50: #092433;

  /* Neutrals: tonos gris-azulados */
  --chat--color-white: #ffffff;
  --chat--color-light: #F0F4F8;
  --chat--color-light-shade-50: #E2E8F0;
  --chat--color-light-shade-100: #CBD5E1;
  --chat--color-medium: #94A3B8;
  --chat--color-dark: #0F172A;
  --chat--color-disabled: #A0AEC0;
  --chat--color-typing: #475569;

  /* ── Base Layout ── */
  --chat--spacing: 1rem;
  --chat--border-radius: 0.5rem;
  --chat--transition-duration: 0.15s;
  --chat--font-family: (
    -apple-system,
    BlinkMacSystemFont,
    'Segoe UI',
    Roboto,
    Oxygen-Sans,
    Ubuntu,
    Cantarell,
    'Helvetica Neue',
    sans-serif
  );

  /* ── Window ── */
  --chat--window--width: 400px;
  --chat--window--height: 620px;
  --chat--window--bottom: var(--chat--spacing);
  --chat--window--right: var(--chat--spacing);
  --chat--window--z-index: 9999;
  --chat--window--border: 1px solid var(--chat--color-light-shade-50);
  --chat--window--border-radius: 0.75rem;
  --chat--window--margin-bottom: var(--chat--spacing);

  /* ── Header: azul profundo con acento primario ── */
  --chat--header-height: auto;
  --chat--header--padding: var(--chat--spacing);
  --chat--header--background: #0F172A;
  --chat--header--color: #F0F4F8;
  --chat--header--border-top: none;
  --chat--header--border-bottom: 2px solid #2A6F9C;
  --chat--header--border-left: none;
  --chat--header--border-right: none;
  --chat--heading--font-size: 1.6em;
  --chat--subtitle--font-size: 0.85em;
  --chat--subtitle--line-height: 1.8;

  /* ── Messages ── */
  --chat--message--font-size: 0.97rem;
  --chat--message--padding: var(--chat--spacing);
  --chat--message--border-radius: 0.75rem;
  --chat--message-line-height: 1.55;
  --chat--message--margin-bottom: calc(var(--chat--spacing) * 0.85);

  /* Bot: fondo gris muy claro azulado */
  --chat--message--bot--background: #F8FAFC;
  --chat--message--bot--color: #0F172A;
  --chat--message--bot--border: 1px solid #E2E8F0;

  /* User: azul primario */
  --chat--message--user--background: #2A6F9C;
  --chat--message--user--color: #ffffff;
  --chat--message--user--border: none;

  --chat--message--pre--background: rgba(15, 23, 42, 0.07);
  --chat--messages-list--padding: var(--chat--spacing);

  /* ── Toggle Button: azul con hover más oscuro ── */
  --chat--toggle--size: 64px;
  --chat--toggle--width: var(--chat--toggle--size);
  --chat--toggle--height: var(--chat--toggle--size);
  --chat--toggle--border-radius: 50%;
  --chat--toggle--background: #2A6F9C;
  --chat--toggle--hover--background: #235E84;
  --chat--toggle--active--background: #1C4D6B;
  --chat--toggle--color: #ffffff;

  /* ── Input Area ── */
  --chat--textarea--height: 50px;
  --chat--textarea--max-height: 30rem;
  --chat--input--font-size: inherit;
  --chat--input--border: 0;
  --chat--input--border-radius: 0;
  --chat--input--padding: 0.8rem;
  --chat--input--background: #F8FAFC;
  --chat--input--text-color: #0F172A;
  --chat--input--line-height: 1.5;
  --chat--input--placeholder--font-size: var(--chat--input--font-size);
  --chat--input--border-active: 0;
  --chat--input--left--panel--width: 2rem;

  /* ── Buttons ── */
  --chat--button--color: #F0F4F8;
  --chat--button--background: #2A6F9C;
  --chat--button--padding: calc(var(--chat--spacing) * 0.5) var(--chat--spacing);
  --chat--button--border-radius: 0.5rem;
  --chat--button--hover--color: #F0F4F8;
  --chat--button--hover--background: #235E84;
  --chat--close--button--color-hover: #2A6F9C;

  /* ── Send & File Buttons ── */
  --chat--input--send--button--background: #F8FAFC;
  --chat--input--send--button--color: #2A6F9C;
  --chat--input--send--button--background-hover: #E2E8F0;
  --chat--input--send--button--color-hover: #1C4D6B;
  --chat--input--file--button--background: #F8FAFC;
  --chat--input--file--button--color: #2A6F9C;
  --chat--input--file--button--background-hover: #F8FAFC;
  --chat--input--file--button--color-hover: #1C4D6B;
  --chat--files-spacing: 0.25rem;

  /* ── Body & Footer: fondo neutro azulado claro ── */
  --chat--body--background: #F0F4F8;
  --chat--footer--background: #F8FAFC;
  --chat--footer--color: #475569;
}

/* Ancho máximo de burbuja */
.chat-message {
  max-width: 78%;
}
